// Build OpenRouter request body for extraction.
const cfg = $json;
const system = `Sei un parser deterministico. Estrai dati da un messaggio utente su un capo di abbigliamento che già possiede. Restituisci SOLO JSON valido con questi campi: brand, size_label, product_group, product_type, fit, gender, target_age. Metti null dove non sai. Non inventare. product_group \u2208 {tops, bottoms}. fit \u2208 {oversize, regular, slim, relaxed}. gender \u2208 {men, women, unisex, kids}. target_age \u2208 {adult, kids, baby}. product_type esempi: tshirt, shirt, hoodie, sweater, blazer, dress, jeans, trousers, shorts.`;
const user = `Messaggio: "${cfg.user_message}"\nEstrai i campi. Output JSON only.`;
return [{ json: {
  ...cfg,
  openrouter_body: {
    model: cfg.modelExtract,
    temperature: 0,
    max_tokens: 300,
    response_format: { type: 'json_object' },
    messages: [
      { role: 'system', content: system },
      { role: 'user',   content: user }
    ]
  }
}}];

// Parse LLM extraction → structured user_refs. Tolerant to fenced JSON.
function safeParse(s){ if(!s) return null; let t=String(s).trim(); const m=t.match(/```(?:json)?\s*([\s\S]*?)```/i); if(m) t=m[1].trim(); try{return JSON.parse(t);}catch(e){} const a=t.indexOf('{'),b=t.lastIndexOf('}'); if(a>=0&&b>a){ try{return JSON.parse(t.slice(a,b+1));}catch(e){} } return null; }
const resp = $json;
const choices = resp.choices || (resp.body && resp.body.choices) || [];
const raw = choices[0]?.message?.content || '';
const parsed = safeParse(raw) || {};
const norm = v => (v == null || v === '' ? null : String(v).trim().toLowerCase());
const user_ref = {
  brand: norm(parsed.brand),
  size_label: parsed.size_label != null ? String(parsed.size_label).trim().toUpperCase() : null,
  product_group: norm(parsed.product_group),
  product_type: norm(parsed.product_type),
  fit: norm(parsed.fit),
  gender: norm(parsed.gender),
  target_age: norm(parsed.target_age)
};
const cfg = $('Config').first().json;
return [{ json: { ...cfg, user_ref, extract_raw: raw } }];

// Normalize + build reference-candidate set and target-size set.
const cfg = $('Config').first().json;
const user_ref = $('Parse Extract').first().json.user_ref || {};

function num(v){
  if (v==null) return null;
  if (typeof v==='number') return isFinite(v)?v:null;
  const s = String(v).trim().replace(',','.');
  if (!s) return null;
  // range like "70 - 76" or "70-76" or "70 to 76" → midpoint
  const range = s.match(/^([0-9]+(?:\.[0-9]+)?)\s*(?:-|–|to)\s*([0-9]+(?:\.[0-9]+)?)$/i);
  if (range) {
    const a = parseFloat(range[1]); const b = parseFloat(range[2]);
    if (isFinite(a) && isFinite(b)) return (a + b) / 2;
  }
  const n = parseFloat(s);
  return isFinite(n) ? n : null;
}
function lc(v){ return v==null ? null : String(v).trim().toLowerCase(); }
function upper(v){ return v==null ? null : String(v).trim().toUpperCase(); }
function normGroup(g){
  if (!g) return null;
  const s = lc(g);
  if (['tops','top','shirt','tshirt','t-shirt','hoodie','sweater','blouse','jacket','blazer','outerwear'].some(k=>s.includes(k))) return 'tops';
  if (['bottoms','pants','trousers','jeans','shorts','skirt'].some(k=>s.includes(k))) return 'bottoms';
  return null;
}

const MEASURES_TOPS    = ['chest','shoulder','sleeve','height'];
const MEASURES_BOTTOMS = ['waist','hip','inseam','thigh'];
const ALL_MEASURES = [...new Set([...MEASURES_TOPS, ...MEASURES_BOTTOMS, 'neck'])];

const rows = $input.all().map(i => i.json);
const normalized = rows.map(r => {
  const grp = normGroup(r.ml_product_group) || normGroup(r.taxonomy_l1) || normGroup(r.ml_product_type);
  const o = {
    brand: lc(r.brand),
    product_url: (r.product_url || '').trim(),
    product_name: r.product_name,
    ml_product_type: lc(r.ml_product_type),
    ml_product_subtype: lc(r.ml_product_subtype),
    ml_product_group: grp,
    ml_gender: lc(r.ml_gender),
    ml_target_age: lc(r.ml_target_age),
    size_label: upper(r.size_label),
    size_system: r.size_system || null,
    leaf_category: r.leaf_category
  };
  for (const k of ALL_MEASURES) o[k] = num(r[k]);
  return o;
});

const target_url = (cfg.target_product_url || '').trim();
const user_group = normGroup(user_ref.product_group) || normGroup(user_ref.product_type);

// Heuristic: if user didn't specify group, try to infer from target rows later.
return [{ json: { ...cfg, user_ref, user_group, target_url, normalized } }];

// 1) Determine target-product group (use target rows if user hasn't said).
// 2) Score reference candidates. 3) Pick best reference.
// 4) Detect ambiguity → if info is too thin, flag needs_clarification with ONE question.
const env = $json;
const { user_ref, normalized, target_url } = env;
let user_group = env.user_group;

const MEASURES_TOPS    = ['chest','shoulder','sleeve','height'];
const MEASURES_BOTTOMS = ['waist','hip','inseam','thigh'];

const targetRows = normalized.filter(r => r.product_url && r.product_url === target_url);
const targetGroupGuess = (() => {
  const groups = targetRows.map(r => r.ml_product_group).filter(Boolean);
  if (!groups.length) return null;
  const cnt = {}; for (const g of groups) cnt[g] = (cnt[g]||0)+1;
  return Object.entries(cnt).sort((a,b)=>b[1]-a[1])[0][0];
})();
if (!user_group) user_group = targetGroupGuess || null;

const measures = user_group === 'bottoms' ? MEASURES_BOTTOMS : MEASURES_TOPS;
function usefulMeasuresCount(r, grp){
  const m = grp === 'bottoms' ? MEASURES_BOTTOMS : (grp === 'tops' ? MEASURES_TOPS : [...MEASURES_TOPS, ...MEASURES_BOTTOMS]);
  return m.filter(k => r[k] != null).length;
}

function scoreReference(row){
  let s = 0;
  if (user_ref.brand && row.brand === user_ref.brand) s += 50;
  if (user_group && row.ml_product_group === user_group) s += 25;
  if (user_ref.product_type && row.ml_product_type === user_ref.product_type) s += 15;
  if (user_ref.product_type && row.ml_product_subtype && row.ml_product_subtype.includes(user_ref.product_type)) s += 10;
  if (user_ref.gender && row.ml_gender === user_ref.gender) s += 10;
  if (user_ref.size_label && row.size_label === user_ref.size_label) s += 5;
  if (user_ref.target_age && row.ml_target_age === user_ref.target_age) s += 3;
  if (user_ref.fit && row.ml_product_subtype && row.ml_product_subtype.includes(user_ref.fit)) s += 5;
  const useful = usefulMeasuresCount(row, user_group);
  if (useful >= 4) s += 10; else if (useful === 3) s += 8; else if (useful === 2) s += 5; else if (useful === 1) s += 2;
  return s;
}

// Filter candidates: need brand to match (with contains fallback).
let candidates = normalized.filter(r => r.brand && user_ref.brand && r.brand === user_ref.brand);
if (!candidates.length && user_ref.brand) {
  const needle = user_ref.brand.toLowerCase();
  candidates = normalized.filter(r => r.brand && r.brand.toLowerCase().includes(needle));
}
// Need at least 1 useful measure overall
candidates = candidates.filter(r => usefulMeasuresCount(r, null) >= 1);
// Prefer same size_label when user provided one
if (user_ref.size_label) {
  const sized = candidates.filter(r => r.size_label === user_ref.size_label);
  if (sized.length) candidates = sized;
}
// If user_group is known with confidence, restrict to that group
if (user_group) {
  const sameGroup = candidates.filter(r => r.ml_product_group === user_group);
  if (sameGroup.length) candidates = sameGroup;
}

// --- Ambiguity detection --------------------------------------------------
// Reason about which ONE question to ask (if any). Priority:
//   1. product_group missing AND candidates span multiple groups  → ask type
//   2. product_type missing AND top candidates span many different types → ask item
//   3. fit missing AND candidates have mixed slim/regular/oversize subtypes → ask fit
function topK(arr, n=5){ return arr.slice(0, n); }
const candGroups = [...new Set(candidates.map(r => r.ml_product_group).filter(Boolean))];
const candTypes  = [...new Set(candidates.map(r => r.ml_product_type).filter(Boolean))];
const FITS = ['slim','regular','oversize','relaxed'];
const candFitHits = new Set();
for (const r of candidates) { const sub = r.ml_product_subtype || ''; for (const f of FITS) if (sub.includes(f)) candFitHits.add(f); }

// Only trigger clarification when the user gave genuinely thin context. Count
// how many signal fields (beyond brand/size) are present; each one sharply
// narrows the reference. Trigger thresholds are calibrated so that
// 'Nike M oversize' (fit present) does NOT ask, while 'L di OVS' does.
const signalsPresent = ['product_group','product_type','fit','gender'].filter(k => user_ref[k]).length;
let clarification = null;
if (candidates.length === 0) {
  clarification = { kind:'no_brand_data' };
} else if (signalsPresent === 0 && !user_ref.product_group && candGroups.length >= 2) {
  // brand+size only, candidates span multiple macro groups → ask tops vs bottoms
  clarification = { kind:'product_group', candidates_groups: candGroups, sample_types: topK(candTypes, 6) };
} else if (signalsPresent === 0 && candTypes.length >= 3) {
  // brand+size only, many different types → ask item type
  clarification = { kind:'product_type', candidates_types: topK(candTypes, 8), group: user_group };
} else if (signalsPresent <= 1 && !user_ref.fit && candFitHits.size >= 2 && candidates.length >= 8) {
  // still thin + candidates spread across multiple fits → ask fit
  clarification = { kind:'fit', fits_seen: [...candFitHits] };
}

const scored = candidates.map(r => ({ row: r, score: scoreReference(r) })).sort((a,b)=>b.score - a.score);
const best = scored[0] || null;
const bestScore = best ? best.score : 0;
const secondScore = scored[1] ? scored[1].score : 0;
// Weak-reference heuristic (only for thin-context users): best is tied/near-tied
if (!clarification && signalsPresent === 0 && best && scored.length >= 3 && (bestScore - secondScore) <= 5 && !user_ref.product_type) {
  clarification = { kind:'product_type', candidates_types: topK(candTypes, 8), group: user_group };
}

return [{ json: { ...env, user_group, targetRows, reference: best ? { row: best.row, score: best.score, candidates_count: candidates.length } : null, clarification } }];

// Score each target size row vs the reference, pick recommended + alternatives.
// Short-circuit when Select Reference flagged a clarification need.
const env = $json;
const { user_group, targetRows, reference, clarification } = env;

const WEIGHTS = {
  tops:    { chest: 0.5, shoulder: 0.25, sleeve: 0.15, height: 0.10 },
  bottoms: { waist: 0.5, hip: 0.25, inseam: 0.15, thigh: 0.10 }
};
const STRONG = { tops: 'chest', bottoms: 'waist' };

// Clarification takes precedence — don't recommend with insufficient info.
if (clarification) {
  return [{ json: { ...env, result: { ok:false, error:'needs_clarification', confidence:'none', clarification } } }];
}
if (!reference) {
  return [{ json: { ...env, result: { ok:false, error:'no_reference_found', confidence:'none', reference_found:false } } }];
}
if (!targetRows || !targetRows.length) {
  return [{ json: { ...env, result: { ok:false, error:'target_product_not_found', confidence:'none' } } }];
}
if (!user_group) {
  return [{ json: { ...env, result: { ok:false, error:'cannot_infer_product_group', confidence:'none' } } }];
}

const refRow = reference.row;
const weights = WEIGHTS[user_group] || WEIGHTS.tops;
const strongKey = STRONG[user_group];

function sizeOrderKey(size_label){
  if (!size_label) return { kind:'unknown', v:9999 };
  const s = String(size_label).trim().toUpperCase();
  const n = parseFloat(s.replace(',','.'));
  if (isFinite(n)) return { kind:'num', v:n };
  const alphaOrder = { XXS:1, XS:2, S:3, M:4, L:5, XL:6, XXL:7, '3XL':8, '4XL':9, '5XL':10 };
  if (alphaOrder[s] != null) return { kind:'alpha', v: alphaOrder[s] };
  return { kind:'unknown', v: 9999 };
}

function scoreTarget(tgt){
  let wsum = 0, num = 0;
  const used = [];
  for (const [k, w] of Object.entries(weights)) {
    if (refRow[k] != null && tgt[k] != null && refRow[k] > 0) {
      const diff = Math.abs(tgt[k] - refRow[k]) / refRow[k];
      num += diff * w;
      wsum += w;
      used.push(k);
    }
  }
  const score = wsum > 0 ? num / wsum : null;
  return { score, used, has_strong: used.includes(strongKey) };
}

const scored = targetRows.map(t => ({ row: t, ...scoreTarget(t) })).filter(x => x.score != null);
if (!scored.length) {
  return [{ json: { ...env, result: { ok:false, error:'no_comparable_measurements', confidence:'none', reference_found:true } } }];
}

// Sort: best score first; also compute size ordering for alternatives
scored.sort((a,b) => a.score - b.score);
const best = scored[0];

// Sort target rows by a consistent size order to find neighbors of best
const orderKeyOf = r => sizeOrderKey(r.size_label).v;
const orderedByLabel = [...scored].sort((a,b) => orderKeyOf(a.row) - orderKeyOf(b.row));
const bestIdx = orderedByLabel.findIndex(x => x.row.size_label === best.row.size_label && x.row.product_url === best.row.product_url);
const smaller = bestIdx > 0 ? orderedByLabel[bestIdx-1] : null;
const larger  = bestIdx >= 0 && bestIdx < orderedByLabel.length - 1 ? orderedByLabel[bestIdx+1] : null;

// Confidence
let confidence = 'low';
if (best.score <= 0.05 && best.has_strong) confidence = 'high';
else if (best.score <= 0.10 && best.has_strong) confidence = 'medium';
else if (best.score <= 0.10) confidence = 'medium';
else confidence = 'low';

const result = {
  ok: true,
  reference_found: true,
  reference: {
    brand: refRow.brand,
    product_name: refRow.product_name,
    product_url: refRow.product_url,
    size_label: refRow.size_label,
    ml_product_type: refRow.ml_product_type,
    measurements: Object.fromEntries(Object.keys(weights).map(k => [k, refRow[k] ?? null]))
  },
  recommended_size: best.row.size_label,
  recommended_score: best.score,
  measurements_used: best.used,
  confidence,
  alternative_smaller: smaller ? { size_label: smaller.row.size_label, score: smaller.score } : null,
  alternative_larger:  larger  ? { size_label: larger.row.size_label,  score: larger.score  } : null,
  group: user_group,
  target_product_url: env.target_url,
  reference_match_score: reference.score,
  candidates_count: scored.length
};
return [{ json: { ...env, result } }];

// Build the OpenRouter body for formatting the final natural-language answer.
const env = $json;
const cfg = $('Config').first().json;
const user_ref = $('Parse Extract').first().json.user_ref;
const result = env.result || {};

const system = `Sei un assistente taglie. Scrivi UNA risposta breve (1-3 frasi) in italiano, prima persona, tono semplice, non tecnico. NON mostrare score numerici. Segui il risultato strutturato. Non inventare.\n\nGestione dei casi:\n- result.ok=true: suggerisci recommended_size. Se presente alternative_smaller o alternative_larger, menzionala solo se utile.\n- result.error='needs_clarification': NON dare una raccomandazione. Fai UNA sola domanda chiarificatrice, pertinente e concreta, basata su result.clarification.kind:\n   * kind='product_group' → chiedi se è un top (maglietta, felpa, giacca) o un bottom (pantaloni, shorts, gonna).\n   * kind='product_type' → chiedi il tipo specifico, elencando 3-4 opzioni prese da result.clarification.candidates_types (es: 'è una maglietta, una felpa, una camicia o una giacca?').\n   * kind='fit' → chiedi se il capo di riferimento è slim, regular o oversize (segnala i fit visti in clarification.fits_seen).\n   * kind='no_brand_data' → spiega cortese che non hai abbastanza dati su quel brand.\n- result.error='target_product_not_found' → spiega che non hai trovato il prodotto specifico; chiedi se vuole mandarti il link.\n- result.error='no_reference_found' → chiedi il brand del capo di riferimento.\n- result.error='no_comparable_measurements' → spiega che le misure disponibili non sono confrontabili (probabilmente categorie diverse).\n- result.error='cannot_infer_product_group' → chiedi se è un top o un bottom.`;

const user = JSON.stringify({ user_message: cfg.user_message, user_ref, result });
return [{ json: {
  ...env,
  openrouter_body: {
    model: cfg.modelFormat,
    temperature: 0.4,
    max_tokens: 400,
    messages: [
      { role: 'system', content: system },
      { role: 'user',   content: `Dato questo JSON, formula la risposta finale:\n${user}` }
    ]
  }
}}];

// Assemble the final webhook response payload.
const resp = $json;
const choices = resp.choices || (resp.body && resp.body.choices) || [];
const message = (choices[0]?.message?.content || '').trim() || 'Non sono riuscito a formulare una risposta, riprova.';
const env = $('Score Target Sizes').first().json;
const user_ref = $('Parse Extract').first().json.user_ref;
return [{ json: {
  message,
  user_ref,
  result: env.result
}}];
